const data = msg.payload;
const lastDay = data[data.length - 1];

const values = (lastDay.bodyBatteryValuesArray || [])
    .filter(v => v[1] !== null);

const lastValue = values[values.length - 1];

const activities = lastDay.bodyBatteryActivityEvent || [];
const lastActivity = activities.length > 0 ? activities[activities.length - 1] : null;

const summary = {
    date: lastDay.date,
    current_body_battery: lastValue ? lastValue[1] : null,
    current_timestamp_ms: lastValue ? lastValue[0] : null,
    charged: lastDay.charged,
    drained: lastDay.drained,
    feedback_level: lastDay.bodyBatteryDynamicFeedbackEvent?.bodyBatteryLevel || null,
    feedback_type: lastDay.bodyBatteryDynamicFeedbackEvent?.feedbackShortType || null,
    last_activity_type: lastActivity?.eventType || null,
    last_activity_impact: lastActivity?.bodyBatteryImpact || null,
    last_activity_feedback: lastActivity?.shortFeedback || null
};

msg.payload = JSON.stringify(summary, null, 2);
msg.filename = "/Users/eduardobrito/Documents/GitHub/UNICAMP/android/data/body_battery_summary.json";

return msg;

let data = msg.payload;

// Se vier como Buffer, converte para string
if (Buffer.isBuffer(data)) {
    data = data.toString("utf8");
}

// Se vier como string, tenta fazer JSON.parse
if (typeof data === "string") {
    try {
        data = JSON.parse(data);
    } catch (err) {
        msg.payload = {
            error: "Payload is string but not valid JSON",
            detail: err.message,
            sample: data.slice(0, 200)
        };
        return msg;
    }
}

// Se vier dentro de msg.payload.payload por algum motivo
if (data && data.payload && Array.isArray(data.payload)) {
    data = data.payload;
}

if (!Array.isArray(data) || data.length === 0) {
    msg.payload = {
        error: "No Body Battery data found",
        payload_type: typeof data,
        is_array: Array.isArray(data),
        sample: data
    };
    return msg;
}

const lastDay = data[data.length - 1];

const values = (lastDay.bodyBatteryValuesArray || [])
    .filter(v => v[1] !== null);

const lastValue = values.length > 0 ? values[values.length - 1] : null;

const events = lastDay.bodyBatteryActivityEvent || [];
const lastEvent = events.length > 0 ? events[events.length - 1] : null;

msg.payload = {
    source: "garmin_connect",
    date: lastDay.date,
    current_body_battery: lastValue ? lastValue[1] : null,
    current_timestamp_ms: lastValue ? lastValue[0] : null,
    charged: lastDay.charged,
    drained: lastDay.drained,
    feedback_level: lastDay.bodyBatteryDynamicFeedbackEvent?.bodyBatteryLevel || null,
    feedback_type: lastDay.bodyBatteryDynamicFeedbackEvent?.feedbackShortType || null,
    last_event_type: lastEvent?.eventType || null,
    last_event_impact: lastEvent?.bodyBatteryImpact || null,
    last_event_feedback: lastEvent?.shortFeedback || null
};

return msg;
